const MOTIV_BUILDING = {
  nm: [
    "속보! 마리아관 계단 1분이면 오른다는 사실!!",
    "니콜스 계단 = 가대 1티어 계단.",
  ],
};
function pickMotiv(b, streakVal, isTour) {
  const pool = [...MOTIV_COMMON, ...(MOTIV_BUILDING[b.id] || [])];
  if (isTour && streakVal >= 1)
    pool.push(`연속 출석 ${streakVal}일째, 여기서 끊기 아깝지 않아요?`);
  return pool[Math.floor(Math.random() * pool.length)];
}

/* ---- 날짜 / 연속 이용일(스트릭) 헬퍼 ----
   stamps[hotspotId] = ["YYYY-MM-DD", ...]  (그 계단을 이용한 '날짜'들, 하루 1회) */
const pad = (n) => String(n).padStart(2, "0");
const ymd = (d) =>
  `${d.getFullYear()}-${pad(d.getMonth() + 1)}-${pad(d.getDate())}`;
const parseYmd = (s) => {
  const [y, m, d] = s.split("-").map(Number);
  return new Date(y, m - 1, d);
};
const fmtDay = (s) => {
  if (!s) return "";
  const [, m, d] = s.split("-");
  return `${m}.${d}`;
};
function allDays(obj) {
  const set = new Set();
  Object.values(obj).forEach((arr) => (arr || []).forEach((d) => set.add(d)));
  return set;
}
function currentStreak(obj) {
  const days = allDays(obj);
  if (!days.size) return 0;
  let cur = new Date();
  if (!days.has(ymd(cur))) {
    cur.setDate(cur.getDate() - 1);
    if (!days.has(ymd(cur))) return 0;
  }
  let n = 0;
  while (days.has(ymd(cur))) {
    n++;
    cur.setDate(cur.getDate() - 1);
  }
  return n;
}
function longestStreak(obj) {
  const days = [...allDays(obj)].sort();
  let best = 0,
    run = 0,
    prev = null;
  for (const d of days) {
    if (prev && Math.round((parseYmd(d) - parseYmd(prev)) / 86400000) === 1)
      run++;
    else run = 1;
    best = Math.max(best, run);
    prev = d;
  }
  return best;
}
function normalize(obj) {
  const out = {};
  Object.entries(obj || {}).forEach(([k, v]) => {
    if (Array.isArray(v)) out[k] = [...new Set(v)].sort();
    else if (typeof v === "string") out[k] = [ymd(new Date(v))];
  });
  return out;
}

