/* ---- 진행률 링 ---- */
function Ring({ value, total }) {
  const r = 46,
    c = 2 * Math.PI * r;
  const pct = total ? value / total : 0;
  return (
    <svg viewBox="0 0 120 120" className="ring">
      <circle
        cx="60"
        cy="60"
        r={r}
        fill="none"
        stroke="var(--line)"
        strokeWidth="10"
      />
      <circle
        cx="60"
        cy="60"
        r={r}
        fill="none"
        stroke="var(--yellow)"
        strokeWidth="10"
        strokeLinecap="round"
        strokeDasharray={c}
        strokeDashoffset={c * (1 - pct)}
        transform="rotate(-90 60 60)"
        style={{
          transition: "stroke-dashoffset .7s cubic-bezier(.22,1,.36,1)",
        }}
      />
      <text x="60" y="56" textAnchor="middle" className="ring-num">
        {value}
      </text>
      <text x="60" y="74" textAnchor="middle" className="ring-den">
        / {total}
      </text>
    </svg>
  );
}

/* ---- 수집함 스탬프 배지 (날짜 누적) ---- */
function StampBadge({ h, code, dates, fresh, today }) {
  const got = dates.length > 0;
  const latest = got ? dates[dates.length - 1] : null;
  const usedToday = got && latest === today;
  return (
    <div
      className={`stamp${got ? " got" : ""}${fresh ? " fresh" : ""}`}
      title={got ? `이용한 날: ${dates.map(fmtDay).join(", ")}` : "미수집"}
    >
      <div className="stamp-disc">
        {got && <span className="stamp-count">{dates.length}일</span>}
        <span className="stamp-code">{code}</span>
        <span className="stamp-seg">
          {(h.name.match(/(\d+)\s*$/) || [])[1] || h.floor}
        </span>
        <span className="stamp-stair">{h.floor}층 계단</span>
        {got && <span className="stamp-ring" aria-hidden />}
      </div>
      <div className="stamp-date">
        {got ? (usedToday ? "오늘 기록" : `최근 ${fmtDay(latest)}`) : "미수집"}
      </div>
    </div>
  );
}

